INSERT INTO quizzes (quiz_level, quiz_category, quiz_language, quiz_question, quiz_option_I, quiz_option_II, quiz_option_III, quiz_answer) VALUES
('Medium', 'Science', 'pt-br', 'Qual é a função biológica principal das ''células gliais'' no sistema nervoso humano?', 'Transmitir impulsos elétricos de longa distância', 'Produzir neurotransmissores excitatórios', 'Armazenar memórias de curto prazo', 'Fornecer suporte, nutrição e isolamento aos neurônios'),
