INSERT INTO quizzes (quiz_level, quiz_category, quiz_language, quiz_question, quiz_option_I, quiz_option_II, quiz_option_III, quiz_answer) VALUES
('Hard', 'Science', 'pt-br', 'Qual fenômeno físico é responsável por manter a coesão das nuvens moleculares gigantes contra a pressão térmica, permitindo a formação estelar?', 'Efeito de blindagem magnética', 'Pressão de radiação fotônica', 'Expansão adiabática turbulenta', 'Colapso gravitacional de Jeans'),
('Hard', 'Science', 'en-us', 'Which physical phenomenon is responsible for maintaining the cohesion of giant molecular clouds against thermal pressure, allowing star formation?', 'Magnetic shielding effect', 'Photonic radiation pressure', 'Turbulent adiabatic expansion', 'Jeans gravitational collapse'),
('Hard', 'Science', 'es-es', '¿Qué fenómeno físico es responsable de mantener la cohesión de las nubes moleculares gigantes frente a la presión térmica, permitiendo la formación estelar?', 'Efecto de blindaje magnético', 'Presión de radiación fotónica', 'Expansión adiabática turbulenta', 'Colapso gravitatorio de Jeans'),
('Hard', 'Science', 'pt-br', 'Na bioquímica das membranas celulares, qual é o papel específico do colesterol em temperaturas fisiológicas?', 'Aumentar a permeabilidade a íons hidrogênio', 'Induzir a transição de fase para o estado gel', 'Atuar como precursor enzimático direto', 'Modulador de fluidez e estabilizador de empacotamento'),
('Hard', 'Science', 'en-us', 'In cell membrane biochemistry, what is the specific role of cholesterol at physiological temperatures?', 'Increasing hydrogen ion permeability', 'Inducing phase transition to the gel state', 'Acting as a direct enzymatic precursor', 'Fluidity modulator and packing stabilizer'),
('Hard', 'Science', 'es-es', 'En la bioquímica de las membranas celulares, ¿cuál es el papel específico del colesterol a temperaturas fisiológicas?', 'Aumentar la permeabilidad a iones hidrógeno', 'Inducir la transición de fase al estado de gel', 'Actuar como precursor enzimático directo', 'Modulador de fluidez y estabilizador de empaquetamiento'),
('Hard', 'Science', 'pt-br', 'Qual é a interpretação da mecânica quântica que postula que todas as histórias possíveis de um sistema ocorrem simultaneamente?', 'Interpretação de Copenhagen', 'Teoria de variáveis ocultas de Bohm', 'Colapso objetivo da função de onda', 'Formulação da soma sobre caminhos de Feynman'),
('Hard', 'Science', 'en-us', 'Which quantum mechanics interpretation postulates that all possible histories of a system occur simultaneously?', 'Copenhagen interpretation', 'Bohmian hidden variable theory', 'Objective collapse theory', 'Feynman''s path integral formulation'),
('Hard', 'Science', 'es-es', '¿Cuál es la interpretación de la mecánica cuántica que postula que todas las historias posibles de un sistema ocurren simultáneamente?', 'Interpretación de Copenhague', 'Teoría de variables ocultas de Bohm', 'Colapso objetivo de la función de onda', 'Formulación de la suma sobre caminos de Feynman'),
('Hard', 'Science', 'pt-br', 'O limite de Chandrasekhar determina a massa máxima de uma anã branca antes que ela colapse. Qual é o valor aproximado desse limite em massas solares?', '0,7 massas solares', '2,4 massas solares', '3,2 massas solares', '1,4 massas solares'),
('Hard', 'Science', 'en-us', 'The Chandrasekhar limit determines the maximum mass of a white dwarf before it collapses. What is the approximate value of this limit in solar masses?', '0.7 solar masses', '2.4 solar masses', '3.2 solar masses', '1.4 solar masses'),
('Hard', 'Science', 'es-es', 'El límite de Chandrasekhar determina la masa máxima de una enana blanca antes de que colapse. ¿Cuál es el valor aproximado de este límite en masas solares?', '0,7 masas solares', '2,4 masas solares', '3,2 masas solares', '1,4 masas solares'),
('Hard', 'Science', 'pt-br', 'Em genética molecular, qual é a função principal das proteínas chaperonas?', 'Catalisar a replicação do DNA', 'Degradar proteínas mal dobradas', 'Sinalizar a apoptose celular', 'Auxiliar no dobramento correto de proteínas'),
('Hard', 'Science', 'en-us', 'In molecular genetics, what is the primary function of chaperone proteins?', 'Catalyzing DNA replication', 'Degrading misfolded proteins', 'Signaling cellular apoptosis', 'Assisting in proper protein folding'),
('Hard', 'Science', 'es-es', 'En genética molecular, ¿cuál es la función principal de las proteínas chaperonas?', 'Catalizar la replicación del ADN', 'Degradar proteínas mal plegadas', 'Señalizar la apoptosis celular', 'Ayudar en el plegamiento correcto de proteínas'),
('Hard', 'Science', 'pt-br', 'Qual é a radiação eletromagnética emitida por partículas carregadas que se movem a velocidades relativísticas em campos magnéticos?', 'Radiação de corpo negro', 'Radiação de Hawking', 'Efeito Compton', 'Radiação síncrotron'),
('Hard', 'Science', 'en-us', 'What is the electromagnetic radiation emitted by charged particles moving at relativistic speeds in magnetic fields?', 'Blackbody radiation', 'Hawking radiation', 'Compton effect', 'Synchrotron radiation'),
('Hard', 'Science', 'es-es', '¿Cuál es la radiación electromagnética emitida por partículas cargadas que se mueven a velocidades relativistas en campos magnéticos?', 'Radiación de cuerpo negro', 'Radiación de Hawking', 'Efecto Compton', 'Radiación de sincrotrón'),
('Hard', 'Science', 'pt-br', 'Qual destas leis da termodinâmica estabelece que a entropia de um cristal perfeito a zero absoluto é zero?', 'Primeira Lei', 'Segunda Lei', 'Lei Zero', 'Terceira Lei'),
('Hard', 'Science', 'en-us', 'Which of these laws of thermodynamics states that the entropy of a perfect crystal at absolute zero is zero?', 'First Law', 'Second Law', 'Zeroth Law', 'Third Law'),
('Hard', 'Science', 'es-es', '¿Cuál de estas leyes de la termodinámica establece que la entropía de un cristal perfecto al cero absoluto es cero?', 'Primera Ley', 'Segunda Ley', 'Ley Cero', 'Tercera Ley'),
('Hard', 'Science', 'pt-br', 'Qual isótopo radioativo é o padrão de referência para a definição do segundo no Sistema Internacional de Unidades?', 'Carbono-14', 'Urânio-238', 'Potássio-40', 'Césio-133'),
('Hard', 'Science', 'en-us', 'Which radioactive isotope is the reference standard for the definition of the second in the International System of Units?', 'Carbon-14', 'Uranium-238', 'Potassium-40', 'Cesium-133'),
('Hard', 'Science', 'es-es', '¿Qué isótopo radiactivo es el estándar de referencia para la definición del segundo en el Sistema Internacional de Unidades?', 'Carbono-14', 'Uranio-238', 'Potasio-40', 'Cesio-133'),
('Hard', 'Science', 'pt-br', 'Como é chamada a reação química onde um composto é decomposto pela reação com água?', 'Condensação', 'Oxirredução', 'Polimerização', 'Hidrólise'),
('Hard', 'Science', 'en-us', 'What is the chemical reaction called where a compound is decomposed by reaction with water?', 'Condensation', 'Redox', 'Polymerization', 'Hydrolysis'),
('Hard', 'Science', 'es-es', '¿Cómo se llama la reacción química donde un compuesto es descompuesto por la reacción con agua?', 'Condensación', 'Oxirreducción', 'Polimerización', 'Hidrólisis'),
('Hard', 'Science', 'pt-br', 'Qual princípio físico impede que dois férmions ocupem o mesmo estado quântico simultaneamente?', 'Princípio da incerteza de Heisenberg', 'Teorema de Noether', 'Efeito Casimir', 'Princípio de exclusão de Pauli'),
('Hard', 'Science', 'en-us', 'Which physical principle prevents two fermions from occupying the same quantum state simultaneously?', 'Heisenberg uncertainty principle', 'Noether''s theorem', 'Casimir effect', 'Pauli exclusion principle'),
('Hard', 'Science', 'es-es', '¿Qué principio físico impide que dos fermiones ocupen el mismo estado cuántico simultáneamente?', 'Principio de incertidumbre de Heisenberg', 'Teorema de Noether', 'Efecto Casimir', 'Principio de exclusión de Pauli');
INSERT INTO quizzes (quiz_level, quiz_category, quiz_language, quiz_question, quiz_option_I, quiz_option_II, quiz_option_III, quiz_answer) VALUES
('Hard', 'Science', 'pt-br', 'Qual fenômeno físico é responsável pela radiação de Hawking que causa a evaporação lenta de buracos negros?', 'Efeito Doppler relativístico', 'Efeito Fotoelétrico quântico', 'Decaimento de mésons pi', 'Produção de pares de partículas a partir de flutuações do vácuo no horizonte de eventos'),
('Hard', 'Science', 'en-us', 'Which physical phenomenon is responsible for the Hawking radiation that causes the slow evaporation of black holes?', 'Relativistic Doppler effect', 'Quantum photoelectric effect', 'Pi meson decay', 'Production of particle pairs from vacuum fluctuations at the event horizon'),
('Hard', 'Science', 'es-es', '¿Qué fenómeno físico es responsable de la radiación de Hawking que causa la evaporación lenta de los agujeros negros?', 'Efecto Doppler relativista', 'Efecto fotoeléctrico cuántico', 'Decaimiento de mesones pi', 'Producción de pares de partículas a partir de fluctuaciones del vacío en el horizonte de sucesos'),
('Hard', 'Science', 'pt-br', 'Na teoria da cromodinâmica quântica, o que é o ''confinamento de cor''?', 'A tendência de quarks se alinharem apenas com spins paralelos', 'A impossibilidade de fótons possuírem carga elétrica', 'O colapso da função de onda em sistemas de plasma', 'A impossibilidade de observar um quark isolado devido ao aumento da força de interação com a distância'),
('Hard', 'Science', 'en-us', 'In quantum chromodynamics theory, what is ''color confinement''?', 'The tendency of quarks to align only with parallel spins', 'The impossibility of photons having an electric charge', 'The collapse of the wave function in plasma systems', 'The impossibility of observing an isolated quark due to the increase in interaction force with distance'),
('Hard', 'Science', 'es-es', 'En la teoría de la cromodinámica cuántica, ¿qué es el ''confinamiento de color''?', 'La tendencia de los quarks a alinearse solo con espines paralelos', 'La imposibilidad de que los fotones posean carga eléctrica', 'El colapso de la función de onda en sistemas de plasma', 'La imposibilidad de observar un quark aislado debido al aumento de la fuerza de interacción con la distancia'),
('Hard', 'Science', 'pt-br', 'Qual é o papel da proteína ''Ubiquitina'' no sistema de controle de qualidade celular?', 'Catalisar a replicação do DNA mitocondrial', 'Atuar como neurotransmissor em sinapses inibitórias', 'Facilitar o transporte de oxigênio na hemoglobina', 'Marcar proteínas danificadas ou mal dobradas para degradação no proteassoma'),
('Hard', 'Science', 'en-us', 'What is the role of the ''Ubiquitin'' protein in the cellular quality control system?', 'To catalyze mitochondrial DNA replication', 'To act as a neurotransmitter in inhibitory synapses', 'To facilitate oxygen transport in hemoglobin', 'To tag damaged or misfolded proteins for degradation in the proteasome'),
('Hard', 'Science', 'es-es', '¿Cuál es el papel de la proteína ''Ubiquitina'' en el sistema de control de calidad celular?', 'Catalizar la replicación del ADN mitocondrial', 'Actuar como neurotransmisor en sinapsis inhibitorias', 'Facilitar el transporte de oxígeno en la hemoglobina', 'Marcar proteínas dañadas o mal plegadas para su degradación en el proteasoma'),
('Hard', 'Science', 'pt-br', 'O que descreve a ''Equação de Drake'' no contexto da astrobiologia?', 'A probabilidade de impacto de asteroides em planetas rochosos', 'A taxa de expansão do universo medida pelo desvio para o vermelho', 'A estabilidade de órbitas em sistemas planetários binários', 'Uma estimativa do número de civilizações ativas e comunicativas na Via Láctea'),
('Hard', 'Science', 'en-us', 'What does the ''Drake Equation'' describe in the context of astrobiology?', 'The probability of asteroid impacts on rocky planets', 'The rate of expansion of the universe measured by redshift', 'The stability of orbits in binary planetary systems', 'An estimate of the number of active, communicative civilizations in the Milky Way'),
('Hard', 'Science', 'es-es', '¿Qué describe la ''Ecuación de Drake'' en el contexto de la astrobiología?', 'La probabilidad de impacto de asteroides en planetas rocosos', 'La tasa de expansión del universo medida por el desplazamiento al rojo', 'La estabilidad de órbitas en sistemas planetarios binarios', 'Una estimación del número de civilizaciones activas y comunicativas en la Vía Láctea'),
('Hard', 'Science', 'pt-br', 'Qual é a função do efeito Meissner em materiais supercondutores?', 'Aumentar a resistência elétrica em baixas temperaturas', 'Converter radiação infravermelha em corrente elétrica', 'Prevenir a transição de fase da matéria condensada', 'A expulsão total de campos magnéticos do interior de um supercondutor'),
('Hard', 'Science', 'en-us', 'What is the function of the Meissner effect in superconducting materials?', 'To increase electrical resistance at low temperatures', 'To convert infrared radiation into electric current', 'To prevent the phase transition of condensed matter', 'The total expulsion of magnetic fields from the interior of a superconductor'),
('Hard', 'Science', 'es-es', '¿Cuál es la función del efecto Meissner en materiales superconductores?', 'Aumentar la resistencia eléctrica a bajas temperaturas', 'Convertir la radiación infrarroja en corriente eléctrica', 'Prevenir la transición de fase de la materia condensada', 'La expulsión total de campos magnéticos del interior de un superconductor'),
('Hard', 'Science', 'pt-br', 'No contexto da termodinâmica, o que define a ''Entropia'' segundo a abordagem estatística de Boltzmann?', 'A quantidade de energia térmica convertida em trabalho mecânico', 'A energia interna total de um sistema em equilíbrio', 'A medida de fluxo de elétrons através de uma barreira de potencial', 'O logaritmo do número de microestados correspondentes a um macroestado'),
('Hard', 'Science', 'en-us', 'In the context of thermodynamics, what defines ''Entropy'' according to Boltzmann''s statistical approach?', 'The amount of thermal energy converted into mechanical work', 'The total internal energy of a system at equilibrium', 'The measure of electron flow across a potential barrier', 'The logarithm of the number of microstates corresponding to a macrostate'),
('Hard', 'Science', 'es-es', 'En el contexto de la termodinámica, ¿qué define la ''Entropía'' según el enfoque estadístico de Boltzmann?', 'La cantidad de energía térmica convertida en trabajo mecánico', 'La energía interna total de un sistema en equilibrio', 'La medida del flujo de electrones a través de una barrera de potencial', 'El logaritmo del número de microestados correspondientes a un macroestado'),
('Hard', 'Science', 'pt-br', 'Qual é a principal diferença entre a Mitose e a Meiose II?', 'A meiose II envolve a recombinação gênica por crossing-over', 'A mitose produz quatro células haploides geneticamente distintas', 'A meiose II é precedida pela duplicação dos centríolos', 'A meiose II ocorre em células haploides, enquanto a mitose ocorre em células diploides'),
('Hard', 'Science', 'en-us', 'What is the main difference between Mitosis and Meiosis II?', 'Meiosis II involves gene recombination by crossing-over', 'Mitosis produces four genetically distinct haploid cells', 'Meiosis II is preceded by centriole duplication', 'Meiosis II occurs in haploid cells, while mitosis occurs in diploid cells'),
('Hard', 'Science', 'es-es', '¿Cuál es la principal diferencia entre la Mitosis y la Meiosis II?', 'La meiosis II implica la recombinación genética por entrecruzamiento', 'La mitosis produce cuatro células haploides genéticamente distintas', 'La meiosis II es precedida por la duplicación de los centriolos', 'La meiosis II ocurre en células haploides, mientras que la mitosis ocurre en células diploides'),
('Hard', 'Science', 'pt-br', 'O que é o ''Lenteamento Gravitacional'' previsto pela Relatividade Geral?', 'A distorção da luz ao passar por um campo elétrico intenso', 'O efeito da pressão de radiação na órbita de planetas', 'A reflexão da luz em horizontes de eventos de quasares', 'A curvatura da trajetória da luz causada pela presença de uma massa massiva'),
('Hard', 'Science', 'en-us', 'What is ''Gravitational Lensing'' predicted by General Relativity?', 'The distortion of light when passing through an intense electric field', 'The effect of radiation pressure on planetary orbits', 'The reflection of light off quasar event horizons', 'The bending of the light path caused by the presence of a massive object'),
('Hard', 'Science', 'es-es', '¿Qué es el ''Lente gravitacional'' predicho por la Relatividad General?', 'La distorsión de la luz al pasar por un campo eléctrico intenso', 'El efecto de la presión de radiación en la órbita de los planetas', 'La reflexión de la luz en horizontes de sucesos de cuásares', 'La curvatura de la trayectoria de la luz causada por la presencia de una masa masiva'),
('Hard', 'Science', 'pt-br', 'Na química orgânica, o que caracteriza uma reação de ''Eliminação E2''?', 'A formação de um carbocátion como intermediário', 'A substituição de um grupo funcional por um nucleófilo forte', 'A adição de um próton ao carbono mais substituído', 'Um mecanismo de etapa única onde a base retira o próton simultaneamente à saída do grupo de saída'),
('Hard', 'Science', 'en-us', 'In organic chemistry, what characterizes an ''E2 Elimination'' reaction?', 'The formation of a carbocation as an intermediate', 'The substitution of a functional group by a strong nucleophile', 'The addition of a proton to the most substituted carbon', 'A single-step mechanism where the base removes the proton simultaneously with the leaving group departure'),
('Hard', 'Science', 'es-es', 'En química orgánica, ¿qué caracteriza una reacción de ''Eliminación E2''?', 'La formación de un carbocatión como intermediario', 'La sustitución de un grupo funcional por un nucleófilo fuerte', 'La adición de un protón al carbono más sustituido', 'Un mecanismo de un solo paso donde la base retira el protón simultáneamente a la salida del grupo saliente'),
('Hard', 'Science', 'pt-br', 'Qual é a importância da constante de Planck (h) na física quântica?', 'Determinar a velocidade terminal de partículas subatômicas', 'Definir a força eletromagnética entre quarks', 'Calcular a massa de repouso de partículas sem carga', 'Relacionar a energia de um fóton à sua frequência'),
('Hard', 'Science', 'en-us', 'What is the importance of Planck''s constant (h) in quantum physics?', 'To determine the terminal velocity of subatomic particles', 'To define the electromagnetic force between quarks', 'To calculate the rest mass of chargeless particles', 'To relate the energy of a photon to its frequency'),
('Hard', 'Science', 'es-es', '¿Cuál es la importancia de la constante de Planck (h) en la física cuántica?', 'Determinar la velocidad terminal de partículas subatómicas', 'Definir la fuerza electromagnética entre quarks', 'Calcular la masa de reposo de partículas sin carga', 'Relacionar la energía de un fotón con su frecuencia');
INSERT INTO quizzes (quiz_level, quiz_category, quiz_language, quiz_question, quiz_option_I, quiz_option_II, quiz_option_III, quiz_answer) VALUES
('Hard', 'Science', 'pt-br', 'Qual fenômeno físico é responsável pela ''radiação de Hawking'' permitir que buracos negros percam massa?', 'Efeito Doppler relativístico', 'Decaimento de férmions pesados', 'Aniquilação de matéria escura', 'Criação de pares de partículas virtuais no horizonte de eventos'),
('Hard', 'Science', 'en-us', 'Which physical phenomenon is responsible for ''Hawking radiation'' allowing black holes to lose mass?', 'Relativistic Doppler effect', 'Heavy fermion decay', 'Dark matter annihilation', 'Creation of virtual particle pairs at the event horizon'),
('Hard', 'Science', 'es-es', '¿Qué fenómeno físico es responsable de que la ''radiación de Hawking'' permita a los agujeros negros perder masa?', 'Efecto Doppler relativista', 'Decaimiento de fermiones pesados', 'Aniquilación de materia oscura', 'Creación de pares de partículas virtuales en el horizonte de sucesos'),
('Hard', 'Science', 'pt-br', 'Na química orgânica, o que caracteriza especificamente um sistema ''antiaromático'' segundo a regra de Hückel?', 'Presença de um heteroátomo no anel', 'Substituição por grupos volumosos nos carbonos', 'Configuração geométrica de cadeira', 'Possuir 4n elétrons pi em um sistema cíclico plano'),
('Hard', 'Science', 'en-us', 'In organic chemistry, what specifically characterizes an ''antiaromatic'' system according to Hückel''s rule?', 'Presence of a heteroatom in the ring', 'Substitution with bulky groups on carbons', 'Chair geometric configuration', 'Possessing 4n pi electrons in a planar cyclic system'),
